#nullable enable // autogenerated

using MVZ2.UI;
using UnityEngine;

namespace MVZ2.Talk
{
    public class CharacterPortraitComponent : MonoBehaviour
    {
        public void SetRenderTexture(RenderTexture renderTexture)
        {
            renderCamera.targetTexture = renderTexture;
        }
        public void Render()
        {
            renderCamera.Render();
        }
        public void ChangeVariant(CharacterPortraitViewData viewData)
        {
            layers.updateList(viewData.layers.Length, (i, obj) =>
            {
                var layer = obj.GetComponent<CharacterPortraitComponentLayer>();
                layer.UpdateLayer(viewData.layers[i]);
            });
        }
        public void DestroyGameObject()
        {
            if (gameObject.Exists())
                Destroy(gameObject);
        }
        public Camera renderCamera = null!;
        public ElementList layers = null!;
    }
    public struct CharacterPortraitViewData
    {
        public int width;
        public int height;
        public CharacterPortraitLayerViewData[] layers;
    }
}
